#version 300 es
precision highp float;

// VisualSynth uniforms
uniform float uTime;
uniform float uFrame;
uniform float uFps;
uniform float uRms;

// Audio uniforms
uniform float audioLow;      // bass
uniform float audioLowSmooth; // bass_att
uniform float audioMid;      // mid
uniform float audioMidSmooth; // mid_att
uniform float audioHigh;     // treb
uniform float audioHighSmooth; // treb_att

// Screen uniforms
uniform float uAspectX;
uniform float uAspectY;
uniform vec2 uAspect;
uniform vec2 uTexSize;

// Random values
uniform vec2 uRandomPreset;
uniform vec2 uRandomFrame;

// Input from vertex shader
in vec2 vUv;
in float vRadius;
in float vAngle;

// Output
out vec4 fragColor;

// Textures
uniform sampler2D sampler_main;
uniform sampler2D sampler_noise_lq;
uniform sampler2D sampler_noise_mq;
uniform sampler2D sampler_noise_hq;
uniform sampler2D sampler_blur1;
uniform sampler2D sampler_blur2;
uniform sampler2D sampler_blur3;

// Helper functions
float clamp01(float x) { return clamp(x, 0.0, 1.0); }
vec2 clamp01(vec2 x) { return clamp(x, vec2(0.0), vec2(1.0)); }
vec3 clamp01(vec3 x) { return clamp(x, vec3(0.0), vec3(1.0)); }
vec4 clamp01(vec4 x) { return clamp(x, vec4(0.0), vec4(1.0)); }

// Texture helper functions
vec4 GetPixel(vec2 uv) { return texture(sampler_main, uv); }
vec4 GetBlur1(vec2 uv) { return texture(sampler_blur1, uv); }
vec4 GetBlur2(vec2 uv) { return texture(sampler_blur2, uv); }
vec4 GetBlur3(vec2 uv) { return texture(sampler_blur3, uv); }


void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;


    vec2 d = uTexSize.zw*3;
    vec3 dx = 2*GetBlur1(fract(vUv+vec2(1,0)*d))-2*GetBlur1(fract(vUv-vec2(1,0)*d));
    vec3 dy = 2*GetBlur1(fract(vUv+vec2(0,1)*d))-2*GetBlur1(fract(vUv-vec2(0,1)*d));
    vec3 b1 = GetBlur1(vUv) - 0;
    d *= -1;
    float d2 = d*1.5;
    float1 c1 = 0.042;
    float1 c2 = -0.008;


    vec2 my_uv = vUv - vec2(dx.y,dy.y)*d*0.5 - vec2(dx.x,dy.x)*d2;
    ret.y = texture( sampler_fc_main, my_uv-floor(my_uv)).y;
    ret.y += (ret.y - b1.y)*c1 + c2;


    my_uv = vUv - vec2(dx.x,dy.x)*d*0.5 - vec2(dx.z,dy.z)*d2;
    ret.x = texture( sampler_fc_main, my_uv-floor(my_uv)).x;
    ret.x += (ret.x - b1.x)*c1 + c2;


    my_uv = vUv - vec2(dx.z,dy.z)*d*0.5 - vec2(dx.y,dy.y)*d2;
    ret.z = texture( sampler_fc_main, my_uv-floor(my_uv)).z;
    ret.z += (ret.z - b1.z)*c1 + c2;
//ret = 0;


  fragColor = ret;
}

_shaderData.comp:
#version 300 es
precision highp float;

// VisualSynth uniforms
uniform float uTime;
uniform float uFrame;
uniform float uFps;
uniform float uRms;

// Audio uniforms
uniform float audioLow;      // bass
uniform float audioLowSmooth; // bass_att
uniform float audioMid;      // mid
uniform float audioMidSmooth; // mid_att
uniform float audioHigh;     // treb
uniform float audioHighSmooth; // treb_att

// Screen uniforms
uniform float uAspectX;
uniform float uAspectY;
uniform vec2 uAspect;
uniform vec2 uTexSize;

// Random values
uniform vec2 uRandomPreset;
uniform vec2 uRandomFrame;

// Input from vertex shader
in vec2 vUv;
in float vRadius;
in float vAngle;

// Output
out vec4 fragColor;

// Textures
uniform sampler2D sampler_main;
uniform sampler2D sampler_noise_lq;
uniform sampler2D sampler_noise_mq;
uniform sampler2D sampler_noise_hq;
uniform sampler2D sampler_blur1;
uniform sampler2D sampler_blur2;
uniform sampler2D sampler_blur3;

// Helper functions
float clamp01(float x) { return clamp(x, 0.0, 1.0); }
vec2 clamp01(vec2 x) { return clamp(x, vec2(0.0), vec2(1.0)); }
vec3 clamp01(vec3 x) { return clamp(x, vec3(0.0), vec3(1.0)); }
vec4 clamp01(vec4 x) { return clamp(x, vec4(0.0), vec4(1.0)); }

// Texture helper functions
vec4 GetPixel(vec2 uv) { return texture(sampler_main, uv); }
vec4 GetBlur1(vec2 uv) { return texture(sampler_blur1, uv); }
vec4 GetBlur2(vec2 uv) { return texture(sampler_blur2, uv); }
vec4 GetBlur3(vec2 uv) { return texture(sampler_blur3, uv); }


void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;

float cutoff = 0.95;
int n = 1;
float s = 0.3;

   vec2 c = (vUv-0.5)*2*uAspect.wz;
   numerator = (c + vec2(q21,q22))*64;
   denominator = c + vec2(q23,q24);
   fraction = vec2( numerator.x*denominator.x + numerator.y*denominator.y,
                      numerator.y*denominator.x - numerator.x*denominator.y)/
                      (denominator.x*denominator.x + denominator.y*denominator.y);
   c = fraction-0.5;
   float1 ang_hq = n*atan(c.x,c.y);
   vec2 spiral = vec2(ang_hq*q25+q26,s*uAspect.w*log(length(c))+q27);
   vUv = 0.5 + (0.5 - abs( fract( spiral * 0.5 ) * 2.0 - 1.0 ))*cutoff; // mirror

vec2 uvo = vUv;
vec2 d = uTexSize.zw*3;
vec3 dx = GetBlur1(vUv + vec2(1,0)*d) - GetBlur1(vUv - vec2(1,0)*d);
vec3 dy = GetBlur1(vUv + vec2(0,1)*d) - GetBlur1(vUv - vec2(0,1)*d);
vUv+=vec2(dx.y,dy.y)*vRadius*0.3;

d = uTexSize.zw*16;
dx = GetBlur2(vUv + vec2(1,0)*d) - GetBlur2(vUv - vec2(1,0)*d);
dy = GetBlur2(vUv + vec2(0,1)*d) - GetBlur2(vUv - vec2(0,1)*d);

ret = mix(ret, (1-GetPixel(vUv).x)*vec3(1.5,2.5,3),clamp01(GetBlur1(vUv).x*2)*0.5);

ret = mix(ret*vRadius,vec3(1,0.75,0),(((dy+dx).z*0.43+0.5)*GetBlur2(vUv+vec2(dx.z,dy.z)*uTexSize.zw*32).z));

ret = mix(ret,vec3(1.5,2,3),GetPixel(uvo).y*(0.4-vRadius*0.7));


  fragColor = ret;
}
